import path from 'path';
import jsdom from 'jsdom';
import fs from 'fs'; 

var svgfile
const vextabRenderSvg = (content, {
  width = 640,
  offset = [0, 0],
  ...options
} = {}) => new Promise((resolve, reject) => {
  const { JSDOM, VirtualConsole } = jsdom;
  const virtualConsole = new VirtualConsole();

  virtualConsole
    .on('error', (err) => { reject(err); })
    .on('jsdomError', (err) => { reject(err); });

  const { window } = new JSDOM(`
    <!DOCTYPE html>
    <body><div id="target"></div></body>
    <script id="vextab"></script>
  `, {
    virtualConsole,
    runScripts: 'dangerously',
    resources: 'usable',
  });

  var filepath = '/'
  const { document, MutationObserver } = window;

    // Observer 콜백 함수에서 SVG 문자열을 파일로 저장하는 부분 추가
    const saveToFile = (svgString) => {
      fs.writeFile(filepath, svgString, 'utf8', (err) => {
        if (err) {
          reject(err);
        } else {
          resolve(filepath);
        }
      });
    };

  const observer = new MutationObserver((mutations) => {
    const svgString = mutations[0].target.innerHTML;
    saveToFile(svgString);
    resolve(svgString);
    

  });
  
  const target = document.getElementById('target');
  observer.observe(target, { childList: true });

  window.eval(`
    const data = \`${content}\`;
    const script = document.getElementById('vextab');
    script.onload = () => {
      try {
        const { VexTab, Artist, Vex } = vextab;
        const Renderer = Vex.Flow.Renderer;

        const renderer = new Renderer('target', Renderer.Backends.SVG);
        const artist = new Artist(${offset[0]}, ${offset[1]}, ${width}, ${JSON.stringify(options)});
        const tab = new VexTab(artist);

        tab.parse(data);
        artist.render(renderer);
      } catch (err) {
        console.error(err); 
      }
   };
   script.src = 'file://${path.resolve(process.cwd(), 'node_modules/vextab/dist/main.prod.js')}';
  `);

});

export default vextabRenderSvg;
